export const meta = {
  name: 'sqp-v2-improve-debates',
  description: 'SQP仪表盘V2改进:5业务议题正反辩论达成共识 + UX部署版重设计 + 业务/UX双审查',
  phases: [
    { title: '辩论R1', detail: '5议题各正反方开场立论(接地真实数据)' },
    { title: '辩论R2', detail: '各方看到对方立论后针对性反驳/让步' },
    { title: '共识', detail: '中立整合人产出共识点+争议点+V3动作' },
    { title: 'UX设计', detail: '部署版ECharts重设计方案' },
    { title: '审查', detail: '业务共识审查 + UX方案审查' },
  ],
}

const BRIEF = 'C:\\Users\\EDY\\AppData\\Local\\Temp\\claude\\D--nexgaios-amazon\\3813589b-7399-4352-afc4-07c1ea4f4afb\\scratchpad\\debate_brief.md'
const read = `第一步:用 Read 工具读简报 ${BRIEF}(含全部业务背景/组合/口径/文件位置/议题正反命题)。再读你论证需要的真实数据(V2 HTML 的 INSIGHTS/DATA 片段、对应 SQP CSV、必要时领星 lingxing_mcp sid=7481)。用真实数字与文件证据,禁止空谈。`

const POSITION = { type:'object', additionalProperties:false, properties:{
  stance:{type:'string'},
  claims:{type:'array', items:{type:'object', additionalProperties:false, properties:{claim:{type:'string'}, evidence:{type:'string'}}, required:['claim','evidence']}},
  concessions:{type:'array', items:{type:'string'}},
  strongest_point:{type:'string'}
}, required:['stance','claims','strongest_point'] }

const CONSENSUS = { type:'object', additionalProperties:false, properties:{
  topic_id:{type:'string'}, title:{type:'string'},
  agreements:{type:'array', items:{type:'object', additionalProperties:false, properties:{point:{type:'string'}, evidence:{type:'string'}}, required:['point','evidence']}},
  disputes:{type:'array', items:{type:'object', additionalProperties:false, properties:{point:{type:'string'}, pro_view:{type:'string'}, con_view:{type:'string'}, evidence:{type:'string'}, why_unresolved:{type:'string'}}, required:['point','pro_view','con_view']}},
  recommendation:{type:'string'},
  v3_actions:{type:'array', items:{type:'string'}},
  confidence:{type:'string'}
}, required:['topic_id','title','agreements','recommendation','v3_actions'] }

const TOPICS = [
  { id:'1', title:'B1 叙事锚点重构', pro:'以"2026 H1 vs 2025 H1 同期对比"为固定主叙事,控件降级为图表下钻,即可从根上消解"解读与控件脱钩",且对下半年决策足够。', con:'H1-vs-H1 固定叙事丢掉 Q4 旺季(全年约43%在Nov+Dec)这一决胜盘,把淡季当全年、可能误导下半年备货/投放,需多锚点或别的方案。' },
  { id:'2', title:'B2/I2 可比篮子', pro:'跨期比较只在"两期交集关键词"可比篮子上算,并用 n_kw/sv_all 披露覆盖率;绝对机会一律改为"可比篮子份额缺口→单量、标同口径下限"。', con:'交集法系统性偏向成熟常驻词、漏掉新兴/流失词(恰是增长信号),且交集覆盖率可能过低不代表市场;应用固定策展篮子或分层口径等其他方法。' },
  { id:'3', title:'I1 价格/价值打法', pro:'价格不是可用杠杆(成本刚性、S2毛利仅19%);漏斗漏点靠价值传达+选择性Coupon/Bundle修复,中位价图只作定位解释、不指向降价。', con:'在$60中位价市场卖$240-700,价格/价值错配可能才是转化落后真因;只改图文治标;某些SKU/词可能需结构性定价动作(Bundle重定价/入门变体/旺季促销)。' },
  { id:'4', title:'I3 组合/Hero口径重建', pro:'废弃"单Hero B0DHPN1DMJ vs 品牌"口径,重建为5 ASIN/4父体组合视图,X家族按父体B0DHZM8P16合并,明确真爆款是X2,集中度同口径重算。', con:'组合视图稀释单品可诊断性、增复杂度;SQP各ASIN视图Top100词篮子不同、跨ASIN不可直接相加;"谁是Hero"取决口径,未必要推翻单品视角。' },
  { id:'5', title:'I4+I5 利润护栏与优先级重排', pro:'增长优先级必须按毛利重排(给最低毛利S2冲量是毁价值,应向X1 37%/S1 28%倾斜),仪表盘必须引入利润护栏,并修正乐观双标(AOV−8%、以价换量、单月小样本同比局限显性化)。', con:'毛利是快照、受广告/促销分摊与生命周期影响;单看平均毛利误杀走量担当(S2/X2是流量与排名入口,战略价值≠毛利);"冲量毁价值"要看边际而非平均;份额层面的赢确有其真。' },
]

async function debateTopic(t){
  const ctx = `${read}\n\n【议题${t.id}:${t.title}】(详见简报第五节议题${t.id})`
  const [proR1, conR1] = await parallel([
    ()=>agent(`${ctx}\n你是【正方】。要论证的命题:${t.pro}\n用真实证据充分论证命题成立,并列出你愿意承认的对方可能正确之处。`, {label:`T${t.id}-正R1`, phase:'辩论R1', agentType:'general-purpose', schema:POSITION}),
    ()=>agent(`${ctx}\n你是【反方】。正方命题:${t.pro}\n你的反命题:${t.con}\n用真实证据论证正方命题不成立或有更优解。`, {label:`T${t.id}-反R1`, phase:'辩论R1', agentType:'general-purpose', schema:POSITION}),
  ])
  const [proR2, conR2] = await parallel([
    ()=>agent(`${ctx}\n你是【正方·第二轮】。反方一轮观点:${JSON.stringify(conR1)}\n针对性回应:哪些点你接受(concede)、哪些坚持并补新证据。目标是逼近共识、不为辩而辩。`, {label:`T${t.id}-正R2`, phase:'辩论R2', agentType:'general-purpose', schema:POSITION}),
    ()=>agent(`${ctx}\n你是【反方·第二轮】。正方一轮观点:${JSON.stringify(proR1)}\n针对性回应:哪些点你接受、哪些坚持并补新证据。目标是逼近共识、不为辩而辩。`, {label:`T${t.id}-反R2`, phase:'辩论R2', agentType:'general-purpose', schema:POSITION}),
  ])
  return await agent(`${ctx}\n你是【中立共识整合人】。以下是双方两轮辩论:\n正方R1:${JSON.stringify(proR1)}\n反方R1:${JSON.stringify(conR1)}\n正方R2:${JSON.stringify(proR2)}\n反方R2:${JSON.stringify(conR2)}\n\n必要时自行再核验数据。产出该议题的:①已达成共识点(每条附证据)②仍存争议点(双方各自观点+各自证据+为何未决)③最终建议④V3仪表盘可执行动作(v3_actions)。topic_id填"${t.id}"。`, {label:`T${t.id}-共识`, phase:'共识', agentType:'general-purpose', schema:CONSENSUS})
}

const UX_PROMPT = `${read}\n\n你是资深数据产品/信息设计专家。为这个 SQP 老板汇报仪表盘出一份【部署版重设计方案】。已定方向:部署到阿里云、引入 ECharts 组件库、加访问控制(含利润/份额敏感数据)。叙事将锚定"2026H1 vs 2025H1 同期对比"(固定口径,不做每月动态重算)。

必须解决的已知 UX 问题(来自上一轮真机审查):①解读文案与控件脱钩(改为固定H1锚点叙事,控件仅图表下钻并显式标注口径)②图例不可点选+年对年8条线拥挤+缺"实线26/虚线25"说明③配色色盲不友好(曝光#7aa5ff与点击#2f6df6几乎同色)④Q5"守/抢/扩"动作分类被渲染丢弃⑤无回到顶部+导航不吸顶⑥主次双轴天然误导(建议指数化到基期=100的单轴替代)⑦"精炼卡"是文字墙(拆一句话头条+2-3要点)⑧固定宽1440无响应式⑨tooltip无边界翻转⑩可访问性(键盘可达/aria/focus)⑪多处字号<14px。

充分运用数据可视化与信息设计最佳实践(可参考 dataviz / design-critique / accessibility-review / design-system 的原则:色盲安全分类色板、图表选型、信息层级、无障碍WCAG AA)。产出:①总体信息架构与叙事流(老板30秒抓重点)②每个模块的图表选型与ECharts实现要点(交互/图例/tooltip/双轴替代)③配色与排版规范(含深浅色、色盲安全)④响应式与导航⑤无障碍清单⑥部署与访问控制建议⑦优先级(先做哪3件)。用中文Markdown,具体可落地,别泛泛而谈。`

phase('辩论R1')
const [consensus, ux] = await parallel([
  ()=> parallel(TOPICS.map(t=>()=>debateTopic(t))),
  ()=> agent(UX_PROMPT, {label:'UX重设计方案', phase:'UX设计', agentType:'general-purpose'}),
])

phase('审查')
const [bizReview, uxReview] = await parallel([
  ()=> agent(`${read}\n你是独立【业务审查员】。下面是5个业务议题的辩论共识结论(JSON):\n${JSON.stringify(consensus)}\n\n逐条审查:①每个共识/建议的数字是否真的接地在真实数据(抽查SQP CSV/领星,发现夸大或无据即指出)②5个议题之间有无自相矛盾③"最终建议/V3动作"是否可执行、有无遗漏关键风险④是否仍有把观点当数据的地方。用中文Markdown,分"确认成立/需修正/仍存疑"三档,每条附证据。`, {label:'业务审查', phase:'审查', agentType:'general-purpose'}),
  ()=> agent(`${read}\n你是独立【UX审查员】。下面是UX部署版重设计方案:\n${ux}\n\n审查:①是否真的修复了11条已知问题、有无遗漏②ECharts选型/交互是否可落地、有无过度设计③配色是否真色盲安全(给出对比度/色相判断)④无障碍是否达WCAG AA⑤老板汇报场景下30秒可读性是否达标⑥部署+访问控制建议是否到位。用中文Markdown,分"到位/需加强/缺失"三档,每条给具体改进。`, {label:'UX审查', phase:'审查', agentType:'general-purpose'}),
])

return { consensus, ux, bizReview, uxReview }

